mapper.select:
SELECT post_id, post_uuid, title, content_html, content_text, author_id, menu_key, template_code, parent_id, group_id, depth, order_no, is_secret, view_count, status, metadata, summary_text, keywords_json, ai_language_code, ai_ready, is_notice, notice_start_dt, notice_end_dt, is_popup, popup_start_dt, popup_end_dt, popup_link_url, thumbnail_file_id, popup_dismiss_option, created_at, updated_at, (SELECT COUNT(*) FROM com_file WHERE pgm_id='post' AND ref_id=CAST(post_id AS VARCHAR) AND is_deleted=FALSE) AS file_count, (SELECT COUNT(*) FROM com_comment WHERE pgm_id='post' AND ref_id=CAST(post_id AS VARCHAR) AND is_deleted=FALSE) AS comment_count, (SELECT file_id FROM com_file WHERE pgm_id='post' AND ref_id=CAST(post_id AS VARCHAR) AND is_deleted=FALSE AND file_usage='attachment' ORDER BY ins_dt ASC LIMIT 1) AS first_file_id FROM common_post WHERE is_deleted = FALSE
AND menu_key = #{menuKey}
AND template_code = #{templateCode}
AND title LIKE CONCAT('%', #{keyword}, '%')
AND content_text LIKE CONCAT('%', #{keyword}, '%')
AND author_id LIKE CONCAT('%', #{keyword}, '%')
AND (title LIKE CONCAT('%', #{keyword}, '%') OR content_text LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY ${sortField} ${sortOrder}
ORDER BY order_no ASC, created_at DESC
LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE common_post
SET order_no = order_no + 1
WHERE group_id = #{groupId}
  AND order_no >= #{orderNo}
  AND is_deleted = FALSE

UPDATE common_post
SET group_id = #{articleId}
WHERE post_id = #{articleId} AND is_deleted = FALSE

UPDATE common_post
SET is_deleted = TRUE, deleted_at = NOW(), updated_at = NOW()
WHERE post_id = #{articleId}

mapper.select:
SELECT post_id
FROM common_post
WHERE is_deleted = FALSE
  AND menu_key = #{menuKey}
  AND template_code = #{templateCode}


    AND (
        ${sortField} < (SELECT ${sortField} FROM common_post WHERE post_id = #{articleId})
        OR (
            ${sortField} = (SELECT ${sortField} FROM common_post WHERE post_id = #{articleId})
            AND post_id < #{articleId}
        )
    )


ORDER BY ${sortField} ${sortOrder}, post_id ${sortOrder}
LIMIT 1

SELECT post_id
FROM common_post
WHERE is_deleted = FALSE
  AND menu_key = #{menuKey}
  AND template_code = #{templateCode}


    AND (
        ${sortField} > (SELECT ${sortField} FROM common_post WHERE post_id = #{articleId})
        OR (
            ${sortField} = (SELECT ${sortField} FROM common_post WHERE post_id = #{articleId})
            AND post_id > #{articleId}
        )
    )


ORDER BY ${sortField} ${sortOrder}, post_id ${sortOrder}
LIMIT 1

SELECT post_id, post_uuid, title, content_html, content_text, author_id, menu_key, template_code, parent_id, group_id, depth, order_no, is_secret, view_count, status, metadata, summary_text, keywords_json, ai_language_code, ai_ready, is_notice, notice_start_dt, notice_end_dt, is_popup, popup_start_dt, popup_end_dt, popup_link_url, thumbnail_file_id, popup_dismiss_option, created_at, updated_at FROM common_post WHERE is_deleted = FALSE AND menu_key = 'BANNER' AND template_code = #{templateCode} AND status = 'PUBLISHED'
AND popup_start_dt IS NOT NULL AND popup_end_dt IS NOT NULL AND popup_start_dt <= #{now} AND popup_end_dt >= #{now}
ORDER BY order_no ASC
LIMIT #{limit}
